mapper.select:
select u.user_id, u.dept_id, u.nick_name, u.user_name, u.email, u.avatar, u.phonenumber, u.invite_code, u.level_detail, u.user_level, u.level, u.sex, u.birthday, u.real_name_status, u.growth_value, u.team_leader_level, u.status, u.del_flag, u.login_ip, u.login_date, u.create_by, u.create_time, u.remark, d.dept_name, d.leader, (select p.user_name from sys_user p where p.user_id = substring_index(u.level_detail, ',', -1) and p.user_id != 0) as parent_user_name from sys_user u left join sys_dept d on u.dept_id = d.dept_id where u.del_flag = '0'
AND u.user_id = #{userId}
AND u.user_name like concat('%', #{userName}, '%')
AND u.status = #{status}
AND u.real_name_status = #{realNameStatus}
AND u.phonenumber like concat('%', #{phonenumber}, '%')
AND date_format(u.create_time,'%Y%m%d') >= date_format(#{params.beginTime},'%Y%m%d')
AND date_format(u.create_time,'%Y%m%d') <= date_format(#{params.endTime},'%Y%m%d')
AND (u.dept_id = #{deptId} OR u.dept_id IN ( SELECT t.dept_id FROM sys_dept t WHERE find_in_set(#{deptId}, ancestors) ))
${params.dataScope}

select distinct u.user_id, u.dept_id, u.user_name, u.nick_name, u.email, u.phonenumber, u.real_name_status, u.status, u.create_time from sys_user u left join sys_dept d on u.dept_id = d.dept_id left join sys_user_role ur on u.user_id = ur.user_id left join sys_role r on r.role_id = ur.role_id where u.del_flag = '0' and r.role_id = #{roleId}
AND u.user_name like concat('%', #{userName}, '%')
AND u.phonenumber like concat('%', #{phonenumber}, '%')
${params.dataScope}

mapper.update:
update sys_user
dept_id = #{deptId}, nick_name = #{nickName}, email = #{email}, phonenumber = #{phonenumber}, sex = #{sex}, birthday = #{birthday}, avatar = #{avatar}, password = #{password}, invite_code = #{inviteCode}, level_detail = #{levelDetail}, user_level = #{userLevel}, level = #{level}, team_leader_level = #{teamLeaderLevel}, pay_password = #{payPassword}, real_name_status = #{realNameStatus}, status = #{status}, login_ip = #{loginIp}, login_date = #{loginDate}, update_by = #{updateBy}, remark = #{remark}, update_time = sysdate()
where user_id = #{userId}

update sys_user
nick_name = #{nickName}, email = #{email}, phonenumber = #{phonenumber}, sex = #{sex}, birthday = #{birthday}, avatar = #{avatar}, remark = #{remark}, update_time = sysdate()
where user_id = #{userId}
